import React from "react";
import "./gallary.css";

const Gallery = ({ galleryItems, onImageClick }) => {
  return (
    <section id="gallery" className="modern-gallery">
      <h1>Gallery</h1>
      <p>Explore our beautiful accommodations.</p>
      <div className="gallery-grid">
        {galleryItems.map((item, index) => (
          <div key={index} className="galleryimg">
            <img
              src={item.image}
              alt={`${item.stayType} - Gallery Item ${index + 1}`}
              onClick={() => onImageClick(item.stayType)}
              style={{ cursor: "pointer" }}
            />
          </div>
        ))}
      </div>
    </section>
  );
};

export default Gallery;
